// No income — using annual_turnover as the income gate (like P-02).
// income + business fields together causes offer Error in QA bureau.
const SLAB = 'Rs.0 to 40 lakhs';
const { appId, res, txnId } = await createSenpAppAndOffer(this,
    {
        'employment.emp_type':           'SELFEMP',
        'employment.annual_turnover':    SLAB,
        'employment.nature_of_business': 'Manufacturer',
        'employment.business_type':      'Proprietorship',
    },
    { removeIncome: true }
);
expect(res.status, 'App Create HTTP').to.equal(200);
expect(appId, 'application_id').to.be.a('string').and.not.be.empty;
await verifyDownstream(this, appId, {
    annual_turnover:    SLAB,
    nature_of_business: 'Manufacturer',
    business_type:      'Proprietorship',
});

const SLAB = 'Rs.40 lakhs to 1.5 Cr.';
const { appId, res, txnId } = await createSenpAppAndOffer(this,
    { 'employment.emp_type': 'SELFEMP', 'employment.annual_turnover': SLAB },
    { removeIncome: true }
);
expect(res.status, 'App Create HTTP').to.equal(200);
await verifyDownstream(this, appId, { annual_turnover: SLAB });

